SELECT brands.brand_name, size_charts.chart_name
FROM size_charts
INNER JOIN brands ON size_charts.brand_id = brands.brand_id;

SELECT COUNT(model_id) AS approved_models
FROM fit_models
WHERE approval_status = 'Approved';

SELECT body_type, COUNT(model_id) AS number_of_fit_models
FROM fit_models
GROUP BY body_type;

SELECT bust_in, waist_in, hip_in, shoulder_in, inseam_in
FROM fit_model_measurements
WHERE model_id = 10;

SELECT fm.model_name, fmv.video_path
FROM fit_models fm
JOIN fit_model_videos fmv ON fm.model_id = fmv.model_id;

SELECT DISTINCT b.brand_name, b.contact_email
FROM brands b
INNER JOIN size_charts sc ON b.brand_id = sc.brand_id;

SELECT b.brand_name, sc.chart_name
FROM brands b
JOIN size_charts sc ON b.brand_id = sc.brand_id;

SELECT model_name, body_type 
FROM fit_models
WHERE gender = 'Men';
